# Data models for a content management system
# Provides interfaces, enums, and base classes

enum ContentStatus:
    Draft = 1
    Published = 2
    Archived = 3

enum UserRole:
    Viewer = 1
    Editor = 2
    Admin = 3

@abstract
class Content:
    title: str
    status: ContentStatus

    def __init__(self, title: str):
        self.title = title
        self.status = ContentStatus.Draft

    @abstract
    def get_type(self) -> str:
        ...

    def publish(self) -> None:
        self.status = ContentStatus.Published

    def archive(self) -> None:
        self.status = ContentStatus.Archived

class User:
    username: str
    role: UserRole

    def __init__(self, username: str, role: UserRole):
        self.username = username
        self.role = role

    def can_edit(self) -> bool:
        return self.role == UserRole.Editor or self.role == UserRole.Admin

    def can_publish(self) -> bool:
        return self.role == UserRole.Admin

