# Concrete content implementations and publishing logic
from data_models import Content, ContentStatus, User, UserRole

class Article(Content):
    author: str
    word_count: int

    def __init__(self, title: str, author: str, word_count: int):
        Content.__init__(self, title)
        self.author = author
        self.word_count = word_count

    def get_type(self) -> str:
        return "Article"

    def get_summary(self) -> str:
        return f"{self.title} by {self.author} ({self.word_count} words)"

class Video(Content):
    duration_minutes: int
    resolution: str

    def __init__(self, title: str, duration: int, resolution: str):
        Content.__init__(self, title)
        self.duration_minutes = duration
        self.resolution = resolution

    def get_type(self) -> str:
        return "Video"

    def get_info(self) -> str:
        return f"{self.title} - {self.duration_minutes}min @ {self.resolution}"

class ContentManager:
    published_count: int

    def __init__(self):
        self.published_count = 0

    def process_content(self, content: Content, user: User) -> bool:
        if user.can_publish():
            content.publish()
            self.published_count += 1
            return True
        return False
